// ============================================================
// Secure Key Management
// ============================================================

class SecureKeyManager {
  constructor() {
    this.encryptionKey = null;
  }

  // Derive encryption key from a password using PBKDF2
  deriveKey(password, salt) {
    return crypto.pbkdf2Sync(password, salt, 100000, 32, 'sha256');
  }

  // Encrypt private key for storage
  encryptPrivateKey(privateKey, password) {
    const salt = crypto.randomBytes(16);
    const key = this.deriveKey(password, salt);
    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipheriv('aes-256-gcm', key, iv);
    let encrypted = cipher.update(privateKey, 'utf8', 'hex');
    encrypted += cipher.final('hex');
    const authTag = cipher.getAuthTag();
    return {
      encrypted,
      salt: salt.toString('hex'),
      iv: iv.toString('hex'),
      authTag: authTag.toString('hex'),
    };
  }

  // Decrypt private key from storage
  decryptPrivateKey(encryptedData, password) {
    const salt = Buffer.from(encryptedData.salt, 'hex');
    const key = this.deriveKey(password, salt);
    const iv = Buffer.from(encryptedData.iv, 'hex');
    const decipher = crypto.createDecipheriv('aes-256-gcm', key, iv);
    decipher.setAuthTag(Buffer.from(encryptedData.authTag, 'hex'));
    let decrypted = decipher.update(encryptedData.encrypted, 'hex', 'utf8');
    decrypted += decipher.final('utf8');
    return decrypted;
  }

  // Load private key securely from environment
  loadPrivateKey() {
    const pk = process.env.PRIVATE_KEY;
    if (!pk) {
      throw new Error('PRIVATE_KEY environment variable not set');
    }
    // Validate format
    if (!/^0x[0-9a-fA-F]{64}$/.test(pk)) {
      throw new Error('Invalid private key format');
    }
    return pk;
  }
}

// ============================================================
// Transaction Decoder - Understand pending mempool transactions
// ============================================================

class TransactionDecoder {
  constructor() {
    this.routerInterface = new ethers.Interface(UNISWAP_V2_ROUTER_ABI);
    this.knownRouters = new Set([
      CONFIG.UNISWAP_V2_ROUTER.toLowerCase(),
      CONFIG.UNISWAP_V3_ROUTER.toLowerCase(),
      CONFIG.SUSHISWAP_ROUTER.toLowerCase(),
    ]);
    this.swapSignatures = new Map([
      ['0x38ed1739', 'swapExactTokensForTokens'],
      ['0x8803dbee', 'swapTokensForExactTokens'],
      ['0x7ff36ab5', 'swapExactETHForTokens'],
      ['0xfb3bdb41', 'swapETHForExactTokens'],
      ['0x18cbafe5', 'swapExactTokensForETH'],
      ['0x4a25d94a', 'swapTokensForExactETH'],
      ['0x5c11d795', 'swapExactTokensForTokensSupportingFeeOnTransferTokens'],
      ['0xb6f9de95', 'swapExactETHForTokensSupportingFeeOnTransferTokens'],
      ['0x791ac947', 'swapExactTokensForETHSupportingFeeOnTransferTokens'],
    ]);
  }

  isSwapTransaction(tx) {
    if (!tx || !tx.to || !tx.data) return false;
    const toAddress = tx.to.toLowerCase();
    if (!this.knownRouters.has(toAddress)) return false;
    const selector = tx.data.slice(0, 10);
    return this.swapSignatures.has(selector);
  }

  decodeSwap(tx) {
    try {
      const selector = tx.data.slice(0, 10);
      const methodName = this.swapSignatures.get(selector);
      if (!methodName) return null;

      const decoded = this.routerInterface.parseTransaction({
        data: tx.data,
        value: tx.value,
      });

      return {
        method: methodName,
        args: decoded.args,
        path: decoded.args.path || [],
        amountIn: decoded.args.amountIn || tx.value,
        amountOutMin: decoded.args.amountOutMin,
        to: decoded.args.to,
        deadline: decoded.args.deadline,
        gasPrice: tx.gasPrice,
        hash: tx.hash,
        from: tx.from,
        router: tx.to,
      };
    } catch (error) {
      return null;
    }
  }
}

// ============================================================
// Price Oracle - Get prices from multiple DEXes
// ============================================================

class PriceOracle {
  constructor(provider) {
    this.provider = provider;
    this.routers = {
      uniswapV2: new ethers.Contract(
        CONFIG.UNISWAP_V2_ROUTER,
        UNISWAP_V2_ROUTER_ABI,
        provider
      ),
      sushiswap: new ethers.Contract(
        CONFIG.SUSHISWAP_ROUTER,
        UNISWAP_V2_ROUTER_ABI,
        provider
      ),
    };
    this.priceCache = new Map();
    this.CACHE_TTL_MS = 2000; // 2 second cache
  }

  async getAmountsOut(routerName, amountIn, path) {
    const cacheKey = `${routerName}-${amountIn.toString()}-${path.join('-')}`;
    const cached = this.priceCache.get(cacheKey);
    if (cached && Date.now() - cached.timestamp < this.CACHE_TTL_MS) {
      return cached.amounts;
    }

    try {
      const router = this.routers[routerName];
      if (!router) throw new Error(`Unknown router: ${routerName}`);
      const amounts = await router.getAmountsOut(amountIn, path);
      this.priceCache.set(cacheKey, { amounts, timestamp: Date.now() });
      return amounts;
    } catch (error) {
      return null;
    }
  }

  async getPairReserves(factoryAddress, tokenA, tokenB) {
    try {
      const factory = new ethers.Contract(
        factoryAddress,
        UNISWAP_V2_FACTORY_ABI,
        this.provider
      );
      const pairAddress = await factory.getPair(tokenA, tokenB);
      if (pairAddress === ethers.ZeroAddress) return null;

      const pair = new ethers.Contract(
        pairAddress,
        UNISWAP_V2_PAIR_ABI,
        this.provider
      );
      const [reserves, token0] = await Promise.all([
        pair.getReserves(),
        pair.token0(),
      ]);

      return {
        pairAddress,
        reserve0: reserves[0],
        reserve1: reserves[1],
        token0: token0.toLowerCase(),
        tokenA: tokenA.toLowerCase(),
        tokenB: tokenB.toLowerCase(),
      };
    } catch (error) {
      return null;
    }
  }
}

// ============================================================
// Arbitrage Detector - Find cross-DEX price discrepancies
// ============================================================

class ArbitrageDetector {
  constructor(priceOracle) {
    this.priceOracle = priceOracle;
    this.MIN_PROFIT_BPS = 30; // 0.3% minimum profit after gas
  }

  // Find arbitrage between two DEXes for a given token pair
  async findArbitrage(tokenA, tokenB, amountIn) {
    const path = [tokenA, tokenB];
    const reversePath = [tokenB, tokenA];

    // Get prices from both DEXes
    const [uniAmounts, sushiAmounts] = await Promise.all([
      this.priceOracle.getAmountsOut('uniswapV2', amountIn, path),
      this.priceOracle.getAmountsOut('sushiswap', amountIn, path),
    ]);

    if (!uniAmounts || !sushiAmounts) return null;

    const uniOut = uniAmounts[uniAmounts.length - 1];
    const sushiOut = sushiAmounts[sushiAmounts.length - 1];

    // Check both directions
    const opportunities = [];

    // Buy on Uniswap, sell on Sushiswap
    if (uniOut > 0n) {
      const sushiReverse = await this.priceOracle.getAmountsOut(
        'sushiswap',
        uniOut,
        reversePath
      );
      if (sushiReverse) {
        const finalAmount = sushiReverse[sushiReverse.length - 1];
        if (finalAmount > amountIn) {
          const profitBps =
            Number(((finalAmount - amountIn) * 10000n) / amountIn);
          if (profitBps >= this.MIN_PROFIT_BPS) {
            opportunities.push({
              direction: 'UNI_BUY_SUSHI_SELL',
              buyRouter: 'uniswapV2',
              sellRouter: 'sushiswap',
              tokenA,
              tokenB,
              amountIn,
              intermediateAmount: uniOut,
              expectedOut: finalAmount,
              profitBps,
              profit: finalAmount - amountIn,
            });
          }
        }
      }
    }

    // Buy on Sushiswap, sell on Uniswap
    if (sushiOut > 0n) {
      const uniReverse = await this.priceOracle.getAmountsOut(
        'uniswapV2',
        sushiOut,
        reversePath
      );
      if (uniReverse) {
        const finalAmount = uniReverse[uniReverse.length - 1];
        if (finalAmount > amountIn) {
          const profitBps =
            Number(((finalAmount - amountIn) * 10000n) / amountIn);
          if (profitBps >= this.MIN_PROFIT_BPS) {
            opportunities.push({
              direction: 'SUSHI_BUY_UNI_SELL',
              buyRouter: 'sushiswap',
              sellRouter: 'uniswapV2',
              tokenA,
              tokenB,
              amountIn,
              intermediateAmount: sushiOut,
              expectedOut: finalAmount,
              profitBps,
              profit: finalAmount - amountIn,
            });
          }
        }
      }
    }

    return opportunities.length > 0 ? opportunities : null;
  }

  // Estimate gas cost for an arbitrage trade
  async estimateGasCost(provider, gasPrice) {
    // Approximate gas for two swaps
    const estimatedGas = 350000n;
    const gasCost = estimatedGas * gasPrice;
    return gasCost;
  }

  // Check if arbitrage is profitable after gas
  async isProfitableAfterGas(opportunity, provider, gasPrice) {
    const gasCost = await this.estimateGasCost(provider, gasPrice);
    // Only proceed if profit exceeds gas cost by a safety margin
    const minProfit =
      gasCost + ethers.parseEther(CONFIG.MIN_PROFIT_THRESHOLD_ETH.toString());
    return opportunity.profit > minProfit;
  }
}

// ============================================================
// Flashbots Integration - Private transaction submission
// This PREVENTS front-running of our own transactions
// ============================================================

class FlashbotsManager {
  constructor(provider, signer) {
    this.provider = provider;
    this.signer = signer;
    this.flashbotsEndpoint = CONFIG.FLASHBOTS_RPC;
    // Generate a unique identity for Flashbots relay authentication
    this.authSigner = ethers.Wallet.createRandom();
  }

  // Sign a bundle for Flashbots relay
  async signBundle(transactions) {
    const signedTxs = [];
    for (const tx of transactions) {
      const signedTx = await this.signer.signTransaction(tx);
      signedTxs.push(signedTx);
    }
    return signedTxs;
  }

  // Create Flashbots authentication header
  async createAuthHeader(payload) {
    const message = ethers.id(JSON.stringify(payload));
    const signature = await this.authSigner.signMessage(
      ethers.getBytes(message)
    );
    return `${this.authSigner.address}:${signature}`;
  }

  // Submit bundle to Flashbots relay
  // This ensures our transactions are NOT visible in the public mempool
  async submitBundle(signedTransactions, targetBlockNumber) {
    const params = {
      jsonrpc: '2.0',
      id: 1,
      method: 'eth_sendBundle',
      params: [
        {
          txs: signedTransactions,
          blockNumber: `0x${targetBlockNumber.toString(16)}`,
          minTimestamp: 0,
          maxTimestamp: Math.floor(Date.now() / 1000) + 120,
        },
      ],
    };

    const authHeader = await this.createAuthHeader(params);

    try {
      const response = await fetch(this.flashbotsEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-Flashbots-Signature': authHeader,
        },
        body: JSON.stringify(params),
      });

      const result = await response.json();
      if (result.error) {
        console.error('[Flashbots] Bundle submission error:', result.error);
        return null;
      }

      console.log('[Flashbots] Bundle submitted for block', targetBlockNumber);
      return result.result;
    } catch (error) {
      console.error('[Flashbots] Submission failed:', error.message);
      return null;
    }
  }

  // Simulate bundle before submission
  async simulateBundle(signedTransactions, blockNumber) {
    const params = {
      jsonrpc: '2.0',
      id: 1,
      method: 'eth_callBundle',
      params: [
        {
          txs: signedTransactions,
          blockNumber: `0x${blockNumber.toString(16)}`,
          stateBlockNumber: 'latest',
        },
      ],
    };

    const authHeader = await this.createAuthHeader(params);

    try {
      const response = await fetch(this.flashbotsEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-Flashbots-Signature': authHeader,
        },
        body: JSON.stringify(params),
      });

      const result = await response.json();
      return result.result;
    } catch (error) {
      console.error('[Flashbots] Simulation failed:', error.message);
      return null;
    }
  }
}

// ============================================================
// Trade Executor - Builds and submits arbitrage transactions
// Uses protective measures against front-running
// ============================================================

class TradeExecutor {
  constructor(provider, signer, flashbotsManager) {
    this.provider = provider;
    this.signer = signer;
    this.flashbots = flashbotsManager;
    this.nonce = null;
    this.pendingTrades = new Map();
    this.executedTrades = new Set();
  }

  async initialize() {
    this.nonce = await this.provider.getTransactionCount(
      await this.signer.getAddress()
    );
  }

  // Build swap transaction with protective slippage
  buildSwapTx(routerAddress, path, amountIn, minAmountOut, deadline) {
    const routerInterface = new ethers.Interface(UNISWAP_V2_ROUTER_ABI);
    const signerAddress = this.signer.address;

    // Apply slippage protection
    const slippageMultiplier = BigInt(
      Math.floor((1 - CONFIG.SLIPPAGE_TOLERANCE) * 10000)
    );
    const protectedMinOut = (minAmountOut * slippageMultiplier) / 10000n;

    if (path[0].toLowerCase() === CONFIG.WETH.toLowerCase()) {
      return {
        to: routerAddress,
        data: routerInterface.encodeFunctionData('swapExactETHForTokens', [
          protectedMinOut,
          path,
          signerAddress,
          deadline,
        ]),
        value: amountIn,
      };
    } else if (
      path[path.length - 1].toLowerCase() === CONFIG.WETH.toLowerCase()
    ) {
      return {
        to: routerAddress,
        data: routerInterface.encodeFunctionData('swapExactTokensForETH', [
          amountIn,
          protectedMinOut,
          path,
          signerAddress,
          deadline,
        ]),
        value: 0n,
      };
    } else {
      return {
        to: routerAddress,
        data: routerInterface.encodeFunctionData('swapExactTokensForTokens', [
          amountIn,
          protectedMinOut,
          path,
          signerAddress,
          deadline,
        ]),
        value: 0n,
      };
    }
  }

  // Execute arbitrage using Flashbots (private, non-front-runnable)
  async executeArbitrage(opportunity) {
    const tradeId = `${opportunity.direction}-${opportunity.tokenA}-${opportunity.tokenB}-${Date.now()}`;

    if (this.executedTrades.has(tradeId)) {
      console.log('[Executor] Duplicate trade skipped:', tradeId);
      return null;
    }

    console.log('[Executor] Preparing arbitrage:', {
      direction: opportunity.direction,
      profitBps: opportunity.profitBps,
      profit: ethers.formatEther(opportunity.profit),
    });

    const routerAddresses = {
      uniswapV2: CONFIG.UNISWAP_V2_ROUTER,
      sushiswap: CONFIG.SUSHISWAP_ROUTER,
    };

    const deadline = BigInt(
      Math.floor(Date.now() / 1000) + CONFIG.DEADLINE_SECONDS
    );
    const currentBlock = await this.provider.getBlockNumber();
    const feeData = await this.provider.getFeeData();

    // Build the two swap transactions
    const buyTx = this.buildSwapTx(
      routerAddresses[opportunity.buyRouter],
      [opportunity.tokenA, opportunity.tokenB],
      opportunity.amountIn,
      opportunity.intermediateAmount,
      deadline
    );

    const sellTx = this.buildSwapTx(
      routerAddresses[opportunity.sellRouter],
      [opportunity.tokenB, opportunity.tokenA],
      opportunity.intermediateAmount,
      opportunity.amountIn, // At minimum, get back what we put in
      deadline
    );

    // Prepare full transactions with gas parameters
    const baseTx = {
      chainId: 1,
      type: 2, // EIP-1559
      maxFeePerGas: feeData.maxFeePerGas,
      maxPriorityFeePerGas: feeData.maxPriorityFeePerGas,
    };

    const fullBuyTx = {
      ...baseTx,
      ...buyTx,
      nonce: this.nonce,
      gasLimit: 250000n,
    };

    const fullSellTx = {
      ...baseTx,
      ...sellTx,
      nonce: this.nonce + 1,
      gasLimit: 250000n,
    };

    // Sign and submit via Flashbots for front-running protection
    const signedBundle = await this.flashbots.signBundle([
      fullBuyTx,
      fullSellTx,
    ]);

    // Simulate first
    const simulation = await this.flashbots.simulateBundle(
      signedBundle,
      currentBlock + 1
    );

    if (!simulation || simulation.firstRevert) {
      console.log('[Executor] Bundle simulation failed, skipping');
      return null;
    }

    // Calculate actual profit from simulation
    const totalGasUsed = simulation.results.reduce(
      (sum, r) => sum + BigInt(r.gasUsed),
      0n
    );
    const totalGasCost = totalGasUsed * feeData.gasPrice;

    if (opportunity.profit <= totalGasCost) {
      console.log('[Executor] Not profitable after gas, skipping');
      return null;
    }

    // Submit to Flashbots for the next few blocks
    const targetBlock = currentBlock + 1;
    const results = [];

    for (let i = 0; i < 3; i++) {
      const result = await this.flashbots.submitBundle(
        signedBundle,
        targetBlock + i
      );
      if (result) results.push(result);
    }

    if (results.length > 0) {
      this.executedTrades.add(tradeId);
      this.nonce += 2;
      console.log('[Executor] Bundle submitted successfully for blocks', {
        from: targetBlock,
        to: targetBlock + 2,
        expectedProfit: ethers.formatEther(opportunity.profit - totalGasCost),
      });
    }

    return results;
  }
}

// ============================================================
// Mempool Monitor - Watch for large swaps that create arbitrage
// ============================================================

class MempoolMonitor {
  constructor(web3Provider, decoder) {
    this.web3 = new Web3(web3Provider);
    this.decoder = decoder;
    this.pendingSwaps = new Map();
    this.subscription = null;
    this.callbacks = [];
    this.processedTxs = new LRUCache(10000);
  }

  onSwapDetected(callback) {
    this.callbacks.push(callback);
  }

  async start() {
    console.log('[Mempool] Starting mempool monitoring...');

    try {
      this.subscription = await this.web3.eth.subscribe('pendingTransactions');

      this.subscription.on('data', async (txHash) => {
        if (this.processedTxs.has(txHash)) return;
        this.processedTxs.set(txHash, true);

        try {
          const tx = await this.web3.eth.getTransaction(txHash);
          if (!tx) return;

          if (this.decoder.isSwapTransaction(tx)) {
            const decoded = this.decoder.decodeSwap(tx);
            if (decoded) {
              this.pendingSwaps.set(txHash, {
                ...decoded,
                detectedAt: Date.now(),
              });

              // Notify listeners
              for (const cb of this.callbacks) {
                try {
                  await cb(decoded);
                } catch (e) {
                  console.error('[Mempool] Callback error:', e.message);
                }
              }
            }
          }
        } catch (error) {
          // Transaction may have been mined already
        }
      });

      this.subscription.on('error', (error) => {
        console.error('[Mempool] Subscription error:', error.message);
        this.restart();
      });

      console.log('[Mempool] Monitoring active');
    } catch (error) {
      console.error('[Mempool] Failed to start:', error.message);
      throw error;
    }
  }

  async restart() {
    console.log('[Mempool] Restarting...');
    if (this.subscription) {
      try {
        await this.subscription.unsubscribe();
      } catch (e) {
        // ignore
      }
    }
    setTimeout(() => this.start(), 5000);
  }

  async stop() {
    if (this.subscription) {
      await this.subscription.unsubscribe();
      this.subscription = null;
    }
    console.log('[Mempool] Monitoring stopped');
  }
}

// ============================================================
// Simple LRU Cache
// ============================================================

class LRUCache {
  constructor(maxSize) {
    this.maxSize = maxSize;
    this.cache = new Map();
  }

  has(key) {
    return this.cache.has(key);
  }

  get(key) {
    if (!this.cache.has(key)) return undefined;
    const value = this.cache.get(key);
    // Move to end (most recently used)
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key, value) {
    if (this.cache.has(key)) {
      this.cache.delete(key);
    } else if (this.cache.size >= this.maxSize) {
      // Delete oldest entry
      const firstKey = this.cache.keys().next().value;
      this.cache.delete(firstKey);
    }
    this.cache.set(key, value);
  }
}

// ============================================================
// Risk Manager - Prevents excessive losses
// ============================================================

class RiskManager {
  constructor() {
    this.dailyPnL = 0n;
    this.dailyTradeCount = 0;
    this.maxDailyLoss = ethers.parseEther('0.5'); // Max 0.5 ETH daily loss
    this.maxDailyTrades = 50;
    this.maxSingleTradeSize = ethers.parseEther('5'); // Max 5 ETH per trade
    this.consecutiveLosses = 0;
    this.maxConsecutiveLosses = 3;
    this.lastResetDate = new Date().toDateString();
  }

  resetDailyIfNeeded() {
    const today = new Date().toDateString();
    if (today !== this.lastResetDate) {
      this.dailyPnL = 0n;
      this.dailyTradeCount = 0;
      this.consecutiveLosses = 0;
      this.lastResetDate = today;
      console.log('[Risk] Daily counters reset');
    }
  }

  canTrade(tradeSize) {
    this.resetDailyIfNeeded();

    if (tradeSize > this.maxSingleTradeSize) {
      console.log('[Risk] Trade size exceeds maximum');
      return false;
    }

    if (this.dailyTradeCount >= this.maxDailyTrades) {
      console.log('[Risk] Daily trade limit reached');
      return false;
    }

    if (this.dailyPnL < -this.maxDailyLoss) {
      console.log('[Risk] Daily loss limit reached');
      return false;
    }

    if (this.consecutiveLosses >= this.maxConsecutiveLosses) {
      console.log('[Risk] Too many consecutive losses, pausing');
      return false;
    }

    return true;
  }

  recordTrade(pnl) {
    this.dailyPnL += pnl;
    this.dailyTradeCount++;

    if (pnl < 0n) {
      this.consecutiveLosses++;
    } else {
      this.consecutiveLosses = 0;
    }

    console.log('[Risk] Trade recorded:', {
      pnl: ethers.formatEther(pnl),
      dailyPnL: ethers.formatEther(this.dailyPnL),
      dailyTrades: this.dailyTradeCount,
      consecutiveLosses: this.consecutiveLosses,
    });
  }
}

// ============================================================
// Main Bot - Orchestrates all components
// ============================================================

class MEVProtectionBot {
  constructor() {
    this.isRunning = false;
    this.keyManager = new SecureKeyManager();
    this.riskManager = new RiskManager();
    this.decoder = new TransactionDecoder();
    this.stats = {
      startTime: null,
      opportunitiesFound: 0,
      tradesExecuted: 0,
      totalProfit: 0n,
      totalGasSpent: 0n,
    };
  }

  async initialize() {
    console.log('='.repeat(60));
    console.log('  MEV Protection Bot - Secure Arbitrage Strategy');
    console.log('  Uses Flashbots to prevent front-running of OUR trades');
    console.log('='.repeat(60));

    // Load private key securely
    const privateKey = this.keyManager.loadPrivateKey();

    // Initialize providers
    this.ethersProvider = new ethers.WebSocketProvider(CONFIG.RPC_URL);
    this.signer = new ethers.Wallet(privateKey, this.ethersProvider);

    const address = await this.signer.getAddress();
    const balance = await this.ethersProvider.getBalance(address);
    console.log(`[Init] Wallet: ${address}`);
    console.log(`[Init] Balance: ${ethers.formatEther(balance)} ETH`);

    if (balance < ethers.parseEther('0.1')) {
      throw new Error('Insufficient balance for trading');
    }

    // Initialize components
    this.priceOracle = new PriceOracle(this.ethersProvider);
    this.arbDetector = new ArbitrageDetector(this.priceOracle);
    this.flashbots = new FlashbotsManager(this.ethersProvider, this.signer);
    this.executor = new TradeExecutor(
      this.ethersProvider,
      this.signer,
      this.flashbots
    );
    await this.executor.initialize();

    this.mempoolMonitor = new MempoolMonitor(CONFIG.RPC_URL, this.decoder);

    console.log('[Init] All components initialized');
  }

  async start() {
    if (this.isRunning) {
      console.log('[Bot] Already running');
      return;
    }

    this.isRunning = true;
    this.stats.startTime = Date.now();

    // Set up mempool monitoring
    this.mempoolMonitor.onSwapDetected(async (swap) => {
      await this.handleDetectedSwap(swap);
    });

    await this.mempoolMonitor.start();

    // Also run periodic arbitrage scanning
    this.scanInterval = setInterval(
      () => this.periodicArbitrageScan(),
      10000 // Every 10 seconds
    );

    // Stats reporting
    this.statsInterval = setInterval(() => this.reportStats(), 60000);

    console.log('[Bot] Started successfully');

    // Graceful shutdown
    process.on('SIGINT', () => this.stop());
    process.on('SIGTERM', () => this.stop());
  }

  async handleDetectedSwap(swap) {
    // When we detect a large swap in the mempool, check if it creates
    // an arbitrage opportunity across DEXes
    if (!swap.path || swap.path.length < 2) return;

    const tokenA = swap.path[0];
    const tokenB = swap.path[swap.path.length - 1];

    // Only look at significant swaps (> 1 ETH equivalent)
    const minSwapSize = ethers.parseEther('1');
    if (swap.amountIn < minSwapSize) return;

    console.log('[Bot] Large swap detected:', {
      method: swap.method,
      path: swap.path,
      amountIn: ethers.formatEther(swap.amountIn),
      hash: swap.hash,
    });

    // Check for cross-DEX arbitrage opportunity
    // We're looking for price discrepancies, NOT front-running the user
    const testAmount = ethers.parseEther('1');
    const opportunities = await this.arbDetector.findArbitrage(
      tokenA,
      tokenB,
      testAmount
    );

    if (opportunities && opportunities.length > 0) {
      for (const opp of opportunities) {
        await this.evaluateAndExecute(opp);
      }
    }
  }

  async periodicArbitrageScan() {
    if (!this.isRunning) return;

    // Scan common token pairs for arbitrage
    const commonPairs = [
      [CONFIG.WETH, '0x6B175474E89094C44Da98b954EedeAC495271d0F'], // WETH/DAI
      [CONFIG.WETH, '0xA0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48'], // WETH/USDC
      [CONFIG.WETH, '0xdAC17F958D2ee523a2206206994597C13D831ec7'], // WETH/USDT
      [CONFIG.WETH, '0x2260FAC5E5542a773Aa44fBCfeDf7C193bc2C599'], // WETH/WBTC
    ];

    const testAmount = ethers.parseEther('1');

    for (const [tokenA, tokenB] of commonPairs) {
      try {
        const opportunities = await this.arbDetector.findArbitrage(
          tokenA,
          tokenB,
          testAmount
        );

        if (opportunities) {
          for (const opp of opportunities) {
            await this.evaluateAndExecute(opp);
          }
        }
      } catch (error) {
        // Silently continue scanning
      }
    }
  }

  async evaluateAndExecute(opportunity) {
    this.stats.opportunitiesFound++;

    // Risk check
    if (!this.riskManager.canTrade(opportunity.amountIn)) {
      console.log('[Bot] Risk manager blocked trade');
      return;
    }

    // Profitability check including gas
    const feeData = await this.ethersProvider.getFeeData();
    const isProfitable = await this.arbDetector.isProfitableAfterGas(
      opportunity,
      this.ethersProvider,
      feeData.gasPrice
    );

    if (!isProfitable) {
      console.log('[Bot] Opportunity not profitable after gas');
      return;
    }

    console.log('[Bot] Executing profitable arbitrage:', {
      direction: opportunity.direction,
      profitBps: opportunity.profitBps,
      expectedProfit: ethers.formatEther(opportunity.profit),
    });

    try {
      // Execute via Flashbots (our transactions stay private)
      const result = await this.executor.executeArbitrage(opportunity);

      if (result) {
        this.stats.tradesExecuted++;
        this.stats.totalProfit += opportunity.profit;
        this.riskManager.recordTrade(opportunity.profit);
        console.log('[Bot] Trade executed successfully');
      }
    } catch (error) {
      console.error('[Bot] Trade execution failed:', error.message);
      this.riskManager.recordTrade(-ethers.parseEther('0.01')); // Estimate failed gas cost
    }
  }

  reportStats() {
    const uptime = Math.floor((Date.now() - this.stats.startTime) / 1000);
    console.log('\n' + '='.repeat(40));
    console.log('  Bot Statistics');
    console.log('='.repeat(40));
    console.log(`  Uptime: ${Math.floor(uptime / 60)}m ${uptime % 60}s`);
    console.log(`  Opportunities Found: ${this.stats.opportunitiesFound}`);
    console.log(`  Trades Executed: ${this.stats.tradesExecuted}`);
    console.log(
      `  Total Profit: ${ethers.formatEther(this.stats.totalProfit)} ETH`
    );
    console.log('='.repeat(40) + '\n');
  }

  async stop() {
    console.log('\n[Bot] Shutting down gracefully...');
    this.isRunning = false;

    if (this.scanInterval) clearInterval(this.scanInterval);
    if (this.statsInterval) clearInterval(this.statsInterval);

    await this.mempoolMonitor.stop();

    this.reportStats();
    console.log('[Bot] Shutdown complete');
    process.exit(0);
  }
}

// ============================================================
// Entry Point
// ============================================================

async function main() {
  const bot = new MEVProtectionBot();

  try {
    await bot.initialize();
    await bot.start();
  } catch (error) {
    console.error('[Fatal]', error.message);
    process.exit(1);
  }
}

main();

module.exports = {
  MEVProtectionBot,
  SecureKeyManager,
  TransactionDecoder,
  PriceOracle,
  ArbitrageDetector,
  FlashbotsManager,
  TradeExecutor,
  MempoolMonitor,
  RiskManager,
  LRUCache,
  CONFIG,
};